#include <iostream>
#include <string>

std::string label(int value) { return "int:" + std::to_string(value); }
std::string label(const std::string& value) { return "text:" + value; }

int main() {
    char tag{};
    if (!(std::cin >> tag)) return 1;
    if (tag == 'i') { int value{}; if (!(std::cin >> value)) return 1; std::cout << label(value) << '\n'; }
    else if (tag == 's') { std::string value; if (!(std::cin >> value)) return 1; std::cout << label(value) << '\n'; }
    else std::cout << "invalid\n";
}
